import jsPDF from "jspdf"
import autoTable from "jspdf-autotable"
import QRCode from "qrcode"
// Embedded assets
const LOGO_B64 = "data:image/png;base64,"
const SIGNATURE_B64 = "data:image/png;base64,"
const WATERMARK_B64 = "data:image/png;base64,"
const STATIC_QR_B64 = "data:image/jpeg;base64,"
// ─── UPI Config ───────────────────────────────────────────────────────────────
const UPI_ID   = "7448787979@ybl"
const MERCHANT = "TyreTrack Premium Auto Care"

// ─── Colour palette ───────────────────────────────────────────────────────────
const RED: [number, number, number]     = [220, 0, 0]
const DARK: [number, number, number]    = [30, 30, 30]
const GREY_BG: [number, number, number] = [248, 248, 248]
const BORDER: [number, number, number]  = [210, 210, 210]

// ─── Service price map ────────────────────────────────────────────────────────
const SERVICE_PRICES: Record<string, number> = {
  "Wheel Alignment":     800,
  "Wheel Balancing":     400,
  "Foam Wash":           500,
  "Automatic Car Spa":  1500,
  "Multi Branded Tyres": 5000,
  "Interior Cleaning":  1000,
  "Teflon Coating":     3000,
  "Ceramic Coating":    8000,
  "General Service":    2500,
  "Accessories":        1000,
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
function hLine(
  doc: jsPDF,
  x: number,
  y: number,
  w: number,
  color: [number, number, number] = BORDER
) {
  doc.setDrawColor(color[0], color[1], color[2])
  doc.setLineWidth(0.3)
  doc.line(x, y, x + w, y)
}

function textRight(doc: jsPDF, text: string, rightEdge: number, y: number) {
  const tw = doc.getTextWidth(text)
  doc.text(text, rightEdge - tw, y)
}

function fmt(n: number | string): string {
  return Number(n || 0).toLocaleString("en-IN")
}

// ─── Main export ──────────────────────────────────────────────────────────────
export const generateInvoicePdf = async (invoice: any) => {

  // 0. Build dynamic UPI QR for this exact invoice amount
  const upiString =
    `upi://pay?pa=${UPI_ID}&pn=${encodeURIComponent(MERCHANT)}` +
    `&am=${invoice.totalAmount}&cu=INR` +
    `&tn=${encodeURIComponent("Payment for " + (invoice.invoiceId || "Invoice"))}`

  let dynamicQR = STATIC_QR_B64
  try {
    dynamicQR = await QRCode.toDataURL(upiString, {
      width: 300,
      margin: 1,
      color: { dark: "#000000", light: "#ffffff" },
    })
  } catch (e) {
    console.warn("QR generation failed, using static fallback", e)
  }

  // Page constants
  const doc = new jsPDF({ unit: "mm", format: "a4" })
  const PW  = 210
  const PH  = 297
  const ML  = 12
  const MR  = 12
  const CW  = PW - ML - MR  // 186 mm

  // ═══════════════════════════════════════════════════════════════════════
  // 1. TOP RED ACCENT BAR
  // ═══════════════════════════════════════════════════════════════════════
  doc.setFillColor(RED[0], RED[1], RED[2])
  doc.rect(0, 0, PW, 7, "F")

  // ═══════════════════════════════════════════════════════════════════════
  // 2. LOGO  (top-left)
  // ═══════════════════════════════════════════════════════════════════════
  try {
    doc.addImage(LOGO_B64, "PNG", ML, 8, 72, 22)
  } catch (_) {}

  // ═══════════════════════════════════════════════════════════════════════
  // 3. TAX INVOICE LABEL + META  (top-right)
  // ═══════════════════════════════════════════════════════════════════════
  const invoiceDate = new Date(invoice.createdAt || Date.now())
    .toLocaleDateString("en-IN", { day: "2-digit", month: "2-digit", year: "numeric" })

  // "TAX INVOICE" heading
  doc.setFont("helvetica", "bold")
  doc.setFontSize(18)
  doc.setTextColor(RED[0], RED[1], RED[2])
  textRight(doc, "TAX INVOICE", ML + CW, 18)

  // Meta rows
  const metaLabelX = 138
  const metaValX   = 162
  const metaRows = [
    ["Invoice No :", invoice.invoiceId  || "—"],
    ["Date :",       invoiceDate],
    ["Booking ID :", invoice.bookingId  || "—"],
  ]
  let mY = 25
  for (const [label, val] of metaRows) {
    doc.setFont("helvetica", "bold")
    doc.setFontSize(8)
    doc.setTextColor(DARK[0], DARK[1], DARK[2])
    doc.text(label, metaLabelX, mY)
    doc.setFont("helvetica", "normal")
    doc.text(val, metaValX, mY)
    mY += 6
  }

  // ═══════════════════════════════════════════════════════════════════════
  // 4. COMPANY INFO  (below logo)
  // ═══════════════════════════════════════════════════════════════════════
  doc.setFont("helvetica", "bold")
  doc.setFontSize(11.5)
  doc.setTextColor(DARK[0], DARK[1], DARK[2])
  doc.text("TYRETRACK PREMIUM AUTO CARE", ML, 35)

  doc.setFont("helvetica", "normal")
  doc.setFontSize(7.8)
  const compLines = [
    "Owner : Rtn Charles A",
    "107/2 Pasumai Nagar, Mangalam Road, Tiruppur",
    "Phone : 9443738487",
    "GSTIN : 33AAWFT5612K1ZP",
    "PAN : AKDPP7420L   |   HSN/SAC : 40111010",
  ]
  let cy = 40
  for (const line of compLines) {
    doc.text(line, ML, cy)
    cy += 4.2
  }

  // ═══════════════════════════════════════════════════════════════════════
  // 5. DIVIDER
  // ═══════════════════════════════════════════════════════════════════════
  const divY = 62
  doc.setDrawColor(RED[0], RED[1], RED[2])
  doc.setLineWidth(0.6)
  doc.line(ML, divY, ML + CW, divY)

  // ═══════════════════════════════════════════════════════════════════════
  // 6. CUSTOMER DETAILS BOX
  // ═══════════════════════════════════════════════════════════════════════
  const boxY = divY + 3
  const boxH = 32

  // Outer box
  doc.setFillColor(GREY_BG[0], GREY_BG[1], GREY_BG[2])
  doc.setDrawColor(RED[0], RED[1], RED[2])
  doc.setLineWidth(0.5)
  doc.roundedRect(ML, boxY, CW, boxH, 2, 2, "FD")

  // Red header strip inside box
  doc.setFillColor(RED[0], RED[1], RED[2])
  doc.roundedRect(ML, boxY, CW, 6.5, 2, 2, "F")
  doc.rect(ML, boxY + 3, CW, 3.5, "F")  // fill bottom-curve of strip

  doc.setFont("helvetica", "bold")
  doc.setFontSize(8.5)
  doc.setTextColor(255, 255, 255)
  doc.text("CUSTOMER DETAILS", ML + 4, boxY + 4.5)

  // Left / right columns
  const lcX = ML + 3
  const rcX = ML + (CW / 2) + 3
  let   ry  = boxY + 12

  const leftItems  = [
    ["Name",  invoice.customerName || "—"],
    ["Phone", invoice.phone        || "—"],
    ["Email", invoice.email        || "—"],
  ]
  const rightItems = [
    ["Vehicle No",   invoice.vehicleNumber || "—"],
    ["Vehicle Type", invoice.vehicleType   || "—"],
    ["Vehicle KM",   invoice.vehicleKm     || "—"],
  ]

  for (let i = 0; i < leftItems.length; i++) {
    doc.setFontSize(8)
    doc.setTextColor(DARK[0], DARK[1], DARK[2])

    // Left
    doc.setFont("helvetica", "bold")
    doc.text(leftItems[i][0] + " :", lcX, ry)
    doc.setFont("helvetica", "normal")
    doc.text(leftItems[i][1], lcX + doc.getTextWidth(leftItems[i][0] + " :") + 1, ry)

    // Right
    doc.setFont("helvetica", "bold")
    doc.text(rightItems[i][0] + " :", rcX, ry)
    doc.setFont("helvetica", "normal")
    doc.text(rightItems[i][1], rcX + doc.getTextWidth(rightItems[i][0] + " :") + 1, ry)

    ry += 6.5
  }

  // ═══════════════════════════════════════════════════════════════════════
  // 7. WATERMARK (behind services table)
  // ═══════════════════════════════════════════════════════════════════════
  const tableStartY = boxY + boxH + 5
  try {
    doc.saveGraphicsState()
    doc.setGState(new (doc as any).GState({ opacity: 0.045 }))
    doc.addImage(WATERMARK_B64, "PNG", ML + 10, tableStartY + 8, 165, 20)
    doc.restoreGraphicsState()
  } catch (_) {}

  // ═══════════════════════════════════════════════════════════════════════
  // 8. SERVICES TABLE
  // ═══════════════════════════════════════════════════════════════════════
  const rows: any[] = []
  let sn = 1

  // Standard services
  ;(invoice.services || []).forEach((svc: string) => {
    if (svc === "Multi Branded Tyres") return
    const price = SERVICE_PRICES[svc] || 0
    rows.push([sn++, svc, "Rs " + fmt(price)])
  })

  // Tyre brand
  if (invoice.tyreBrand) {
    const tp = Number(invoice.tyrePrice || SERVICE_PRICES["Multi Branded Tyres"] || 0)
    const tq = Number(invoice.tyreQuantity || 1)
    rows.push([sn++, invoice.tyreBrand + " Tyres x " + tq, "Rs " + fmt(tp * tq)])
  }

  // Custom services
  ;(invoice.customServices || []).forEach((cs: any) => {
    if (!cs.serviceName?.trim()) return
    const amt = Number(cs.amount || 0) * Number(cs.quantity || 1)
    rows.push([sn++, cs.serviceName + " x " + (cs.quantity || 1), "Rs " + fmt(amt)])
  })

  autoTable(doc, {
    startY:  tableStartY,
    margin:  { left: ML, right: MR },
    head:    [["#", "Service / Description", "Amount (Rs)"]],
    body:    rows,
    theme:   "grid",
    styles: {
      fontSize:    8.5,
      cellPadding: 3.5,
      textColor:   DARK,
      lineColor:   BORDER,
      lineWidth:   0.2,
    },
    headStyles: {
      fillColor: RED,
      textColor: [255, 255, 255],
      fontStyle: "bold",
      halign:    "left",
      fontSize:  9,
    },
    columnStyles: {
      0: { cellWidth: 12,     halign: "center" },
      1: { cellWidth: "auto"                   },
      2: { cellWidth: 40,     halign: "right", fontStyle: "bold" },
    },
  })

  const afterTableY = (doc as any).lastAutoTable.finalY + 5

  // ═══════════════════════════════════════════════════════════════════════
  // 9. TOTAL BOX  (right-aligned)
  // ═══════════════════════════════════════════════════════════════════════
  const tbW  = 86
  const tbX  = ML + CW - tbW
  let   tbY  = afterTableY

  // Subtotal row
  doc.setFont("helvetica", "normal")
  doc.setFontSize(8.5)
  doc.setTextColor(DARK[0], DARK[1], DARK[2])
  doc.text("Subtotal :", tbX + 4, tbY + 6)
  textRight(doc, "Rs " + fmt(invoice.subtotal), tbX + tbW - 3, tbY + 6)

  hLine(doc, tbX, tbY + 8, tbW)

  // CGST
  tbY += 14
  const cgst = Number((invoice.gst || 0) / 2).toFixed(2)
  doc.text("CGST (9%) :", tbX + 4, tbY)
  textRight(doc, "Rs " + cgst, tbX + tbW - 3, tbY)

  // SGST
  tbY += 6
  const sgst = Number((invoice.gst || 0) / 2).toFixed(2)
  doc.text("SGST (9%) :", tbX + 4, tbY)
  textRight(doc, "Rs " + sgst, tbX + tbW - 3, tbY)

  hLine(doc, tbX, tbY + 2.5, tbW, RED)

  // TOTAL — red filled row
  tbY += 3
  doc.setFillColor(RED[0], RED[1], RED[2])
  doc.rect(tbX, tbY, tbW, 11, "F")
  doc.setFont("helvetica", "bold")
  doc.setFontSize(11)
  doc.setTextColor(255, 255, 255)
  tbY += 8
  doc.text("TOTAL :", tbX + 4, tbY)
  textRight(doc, "Rs " + fmt(invoice.totalAmount), tbX + tbW - 3, tbY)

  // Outer border for total block
  doc.setDrawColor(BORDER[0], BORDER[1], BORDER[2])
  doc.setLineWidth(0.3)
  doc.rect(tbX, afterTableY, tbW, tbY - afterTableY + 3, "D")

  // ═══════════════════════════════════════════════════════════════════════
  // 10. NOTES  (left of total box)
  // ═══════════════════════════════════════════════════════════════════════
  doc.setFont("helvetica", "italic")
  doc.setFontSize(7.2)
  doc.setTextColor(130, 130, 130)
  doc.text("* Goods once sold will not be taken back.",         ML, afterTableY + 8)
  doc.text("* GST split as CGST 9% + SGST 9%.",                ML, afterTableY + 13)
  doc.text("* This is a computer-generated invoice.",           ML, afterTableY + 18)


  // ═══════════════════════════════════════════════════════════════════════
  // 11. QR  (left)  +  SIGNATURE  (right)
  // ═══════════════════════════════════════════════════════════════════════
  const bottomSectionY = tbY + 12
  const qrBoxW  = 58
  const qrBoxH  = 50
  const qrSize  = 34
  const sigBoxW = 62
  const sigBoxH = 50

  // ── QR box ──────────────────────────────────────────────────────────
  doc.setDrawColor(BORDER[0], BORDER[1], BORDER[2])
  doc.setLineWidth(0.3)
  doc.rect(ML, bottomSectionY, qrBoxW, qrBoxH, "D")

  // PhonePe label (purple)
  doc.setFont("helvetica", "bold")
  doc.setFontSize(8)
  doc.setTextColor(106, 27, 154)
  doc.text("PhonePe | UPI", ML + 3, bottomSectionY + 5)

  doc.setFont("helvetica", "normal")
  doc.setFontSize(7)
  doc.setTextColor(DARK[0], DARK[1], DARK[2])
  doc.text("Scan & Pay", ML + 3, bottomSectionY + 10)

  // QR image
  try {
    doc.addImage(dynamicQR, "PNG", ML + 11, bottomSectionY + 12, qrSize, qrSize)
  } catch (_) {
    try {
      doc.addImage(STATIC_QR_B64, "JPEG", ML + 11, bottomSectionY + 12, qrSize, qrSize)
    } catch (__) {}
  }

  // UPI ID below QR
  doc.setFont("helvetica", "normal")
  doc.setFontSize(6.2)
  doc.setTextColor(80, 80, 80)
  const upiLabel = "UPI ID : " + UPI_ID
  const upiLabelW = doc.getTextWidth(upiLabel)
  doc.text(upiLabel, ML + (qrBoxW - upiLabelW) / 2, bottomSectionY + qrBoxH - 5)

  // Amount in red below UPI ID
  doc.setFont("helvetica", "bold")
  doc.setFontSize(7)
  doc.setTextColor(RED[0], RED[1], RED[2])
  const amtLabel = "Rs " + fmt(invoice.totalAmount)
  const amtLabelW = doc.getTextWidth(amtLabel)
  doc.text(amtLabel, ML + (qrBoxW - amtLabelW) / 2, bottomSectionY + qrBoxH - 1)

  // ── Signature box ─────────────────────────────────────────────────────
  const sigBoxX = ML + CW - sigBoxW
  doc.setDrawColor(BORDER[0], BORDER[1], BORDER[2])
  doc.setLineWidth(0.3)
  doc.rect(sigBoxX, bottomSectionY, sigBoxW, sigBoxH, "D")

  doc.setFont("helvetica", "normal")
  doc.setFontSize(7)
  doc.setTextColor(100, 100, 100)
  doc.text("For TYRETRACK PREMIUM AUTO CARE", sigBoxX + 3, bottomSectionY + 5)

  // Signature image
  try {
    doc.addImage(SIGNATURE_B64, "PNG", sigBoxX + 10, bottomSectionY + 10, 40, 18)
  } catch (_) {}

  // Dotted signature line
  doc.setDrawColor(150, 150, 150)
  doc.setLineDashPattern([1, 1], 0)
  doc.line(sigBoxX + 4, bottomSectionY + 32, sigBoxX + sigBoxW - 4, bottomSectionY + 32)
  doc.setLineDashPattern([], 0)

  doc.setFont("helvetica", "bold")
  doc.setFontSize(7.5)
  doc.setTextColor(DARK[0], DARK[1], DARK[2])
  const authText = "Authorised Signatory"
  const authW = doc.getTextWidth(authText)
  doc.text(authText, sigBoxX + (sigBoxW - authW) / 2, bottomSectionY + 37)

  // ═══════════════════════════════════════════════════════════════════════
  // 12. BOTTOM RED FOOTER BAR
  // ═══════════════════════════════════════════════════════════════════════
  const footerY = PH - 14
  doc.setFillColor(RED[0], RED[1], RED[2])
  doc.rect(0, footerY, PW, 14, "F")

  // Thank you text — centred
  doc.setFont("helvetica", "bolditalic")
  doc.setFontSize(9)
  doc.setTextColor(255, 255, 255)
  const ftxt = "Thank you for choosing TYRETRACK Premium Auto Care"
  const ftxtW = doc.getTextWidth(ftxt)
  doc.text(ftxt, (PW - ftxtW) / 2, footerY + 6)

  // Invoice ref line
  doc.setFont("helvetica", "normal")
  doc.setFontSize(7)
  doc.setTextColor(255, 200, 200)
  const refTxt = invoice.invoiceId + "  |  " + new Date().toLocaleDateString("en-IN")
  const refW   = doc.getTextWidth(refTxt)
  doc.text(refTxt, (PW - refW) / 2, footerY + 11)

  // ═══════════════════════════════════════════════════════════════════════
  // 13. SAVE PDF
  // ═══════════════════════════════════════════════════════════════════════
  const pdfBlob = doc.output("blob")

doc.save(
  (invoice.invoiceId || "TyreTrack-Invoice") + ".pdf"
)

return pdfBlob
}